mapper.select:
SELECT remaining_votes FROM hotword_daily_quota
WHERE user_id = #{userId} AND vote_date = #{voteDate}
FOR UPDATE

mapper.update:
UPDATE hotword_daily_quota
SET remaining_votes = remaining_votes - #{count}
WHERE user_id = #{userId}
  AND vote_date = #{voteDate}
  AND remaining_votes >= #{count}

mapper.insert:
INSERT INTO hotword_daily_quota (user_id, vote_date, remaining_votes)
VALUES (#{userId}, #{voteDate}, #{remainingVotes})
ON DUPLICATE KEY UPDATE remaining_votes = #{remainingVotes}
